<?php
namespace App\Domain\Accounting\Services;
use App\Domain\Accounting\Actions\PostJournal;use App\Models\AccountingPostingRule;use Illuminate\Database\Eloquent\Model;
class AutoPoster{public function __construct(private PostJournal $post){}public function postIfConfigured(string $eventType,Model $source,int $amountMinor,array $context=[]):?\App\Models\JournalEntry{if($amountMinor<=0)return null;$rule=AccountingPostingRule::query()->where('event_type',$eventType)->where('is_active',true)->first();if(!$rule)return null;$description=str_replace(['{reference}','{amount_minor}'],[(string)($source->reference??$source->getKey()),(string)$amountMinor],$rule->description_template??$eventType);$base=['member_id'=>$context['member_id']??null,'loan_id'=>$context['loan_id']??null,'branch_id'=>$context['branch_id']??null,'dimensions'=>[...($rule->dimensions??[]),...($context['dimensions']??[])]];return $this->post->execute(['entry_date'=>$context['entry_date']??today()->toDateString(),'source_type'=>$source->getMorphClass(),'source_id'=>$source->getKey(),'event_type'=>$eventType,'description'=>$description,'currency'=>$context['currency']??'NGN','metadata'=>$context['metadata']??null,'lines'=>[[...$base,'ledger_account_id'=>$rule->debit_account_id,'debit_minor'=>$amountMinor,'credit_minor'=>0],[...$base,'ledger_account_id'=>$rule->credit_account_id,'debit_minor'=>0,'credit_minor'=>$amountMinor]]]);}}
